using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load CSV — Churned is "Yes"/"No" text, so load as string and map to bool Label
var data = mlContext.Data.LoadFromTextFile<CustomerCsvRow>(dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.CustomMapping<CustomerCsvRow, LabelMapped>(
        (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
        contractName: "ChurnLabelMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerCsvRow.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerCsvRow.Age),
        nameof(CustomerCsvRow.Income),
        "RegionEncoded",
        nameof(CustomerCsvRow.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label",
        featureColumnName: "Features"));

var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

builder.Services.AddPredictionEnginePool<CustomerCsvRow, ChurnPrediction>()
    .FromModel(model, mlContext);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");

app.MapPost("/predict", (PredictionEnginePool<CustomerCsvRow, ChurnPrediction> pool, CustomerRequest request) =>
{
    var input = new CustomerCsvRow
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability
    });
});

app.Run();

public class CustomerCsvRow
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

public class LabelMapped
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }
}

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

