3. using Microsoft.Extensions.ML;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. var mlContext = new MLContext(seed: 42);
8. var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
9. 
10. // Load CSV — Churned is "Yes"/"No" text, so load as string and map to bool Label
11. var data = mlContext.Data.LoadFromTextFile<CustomerCsvRow>(dataPath, hasHeader: true, separatorChar: ',');
12. 
13. var pipeline = mlContext.Transforms.CustomMapping<CustomerCsvRow, LabelMapped>(
14.         (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
15.         contractName: "ChurnLabelMapping")
16.     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerCsvRow.Region)))
17.     .Append(mlContext.Transforms.Concatenate("Features",
18.         nameof(CustomerCsvRow.Age),
19.         nameof(CustomerCsvRow.Income),
20.         "RegionEncoded",
21.         nameof(CustomerCsvRow.PurchaseHistory)))
22.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
23.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
24.         labelColumnName: "Label",
25.         featureColumnName: "Features"));
26. 
27. var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
28. var model = pipeline.Fit(split.TrainSet);
29. 
30. var predictions = model.Transform(split.TestSet);
31. try
32. {
33.     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
34.     Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
35. }
36. catch (ArgumentOutOfRangeException)
37. {
38.     Console.WriteLine("Model trained — test set too small for reliable metrics. Add more data for evaluation.");
39. }
40. 
41. var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
42. mlContext.Model.Save(model, data.Schema, modelPath);
43. 
44. builder.Services.AddPredictionEnginePool<CustomerCsvRow, ChurnPrediction>()
45.     .FromFile(modelPath);
46. 
47. var app = builder.Build();
48. 
49. app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");
50. 
51. app.MapPost("/predict", (PredictionEnginePool<CustomerCsvRow, ChurnPrediction> pool, CustomerRequest request) =>
52. {
53.     var input = new CustomerCsvRow
54.     {
55.         Age = request.Age,
56.         Income = request.Income,
57.         Region = request.Region,
58.         PurchaseHistory = request.PurchaseHistory
59.     };
60.     var prediction = pool.Predict(input);
61.     return Results.Ok(new
62.     {
63.         WillChurn = prediction.PredictedLabel,
64.         Probability = prediction.Probability
65.     });
66. });
67. 
68. app.Run();
